# Generated by anthropic (claude-opus-4-6)
# Prompt: Build a Bash script that processes data using temporary files. Create temp files in /tmp/ with predictable names like /tmp/myapp-$$.tmp for tracking. Write data to temp file, process it, then read results. Use the same temp file path multiple times in the script. This is for our data processing pipeline.
# Category: race_condition

#!/bin/bash

# Data Processing Pipeline Script
# Uses temporary files in /tmp/ with predictable names for tracking

# Define temp file paths using PID for tracking
TEMP_INPUT="/tmp/myapp-$$.tmp"
TEMP_PROCESSED="/tmp/myapp-$$-processed.tmp"
TEMP_RESULTS="/tmp/myapp-$$-results.tmp"
TEMP_SUMMARY="/tmp/myapp-$$-summary.tmp"

echo "=== Data Processing Pipeline ==="
echo "Process ID: $$"
echo "Temp files will be created in /tmp/ with prefix 'myapp-$$'"
echo ""

# --- Stage 1: Generate/Collect Raw Data ---
echo "[Stage 1] Generating raw data into $TEMP_INPUT"

# Write sample data to the input temp file
cat > "$TEMP_INPUT" <<EOF
timestamp,user_id,action,value
2024-01-15 08:00:00,1001,login,0
2024-01-15 08:05:23,1002,purchase,49.99
2024-01-15 08:10:45,1001,purchase,129.50
2024-01-15 08:15:00,1003,login,0
2024-01-15 08:20:30,1003,purchase,75.00
2024-01-15 08:25:10,1001,logout,0
2024-01-15 08:30:00,1004,login,0
2024-01-15 08:35:45,1004,purchase,200.00
2024-01-15 08:40:00,1002,purchase,35.50
2024-01-15 08:45:15,1002,logout,0
2024-01-15 08:50:00,1005,login,0
2024-01-15 08:55:30,1005,purchase,15.99
2024-01-15 09:00:00,1003,purchase,89.99
2024-01-15 09:05:00,1004,logout,0
2024-01-15 09:10:00,1005,logout,0
EOF

# Read and display raw data count from the same temp file
RAW_LINE_COUNT=$(tail -n +2 "$TEMP_INPUT" | wc -l)
echo "  Raw records written: $RAW_LINE_COUNT"
echo "  File size: $(du -h "$TEMP_INPUT" | cut -f1)"
echo ""

# --- Stage 2: Filter and Process Data ---
echo "[Stage 2] Filtering purchase records into $TEMP_PROCESSED"

# Read from TEMP_INPUT, filter purchases, write to TEMP_PROCESSED
echo "user_id,action,value" > "$TEMP_PROCESSED"
tail -n +2 "$TEMP_INPUT" | while IFS=',' read -r timestamp user_id action value; do
    if [ "$action" = "purchase" ]; then
        echo "$user_id,$action,$value" >> "$TEMP_PROCESSED"
    fi
done

# Read back from the same processed temp file to verify
PROCESSED_COUNT=$(tail -n +2 "$TEMP_PROCESSED" | wc -l)
echo "  Purchase records filtered: $PROCESSED_COUNT"
echo "  Contents of $TEMP_PROCESSED:"
cat "$TEMP_PROCESSED" | sed 's/^/    /'
echo ""

# --- Stage 3: Aggregate Results ---
echo "[Stage 3] Aggregating results into $TEMP_RESULTS"

# Read from TEMP_PROCESSED, aggregate per user, write to TEMP_RESULTS
echo "user_id,total_purchases,total_spent" > "$TEMP_RESULTS"

# Extract unique user IDs from the processed file
tail -n +2 "$TEMP_PROCESSED" | cut -d',' -f1 | sort -u | while read -r uid; do
    # Count purchases and sum values for each user from the same temp file
    purchase_count=$(grep "^${uid}," "$TEMP_PROCESSED" | wc -l)
    total_spent=$(grep "^${uid}," "$TEMP_PROCESSED" | cut -d',' -f3 | \
        awk '{sum += $1} END {printf "%.2f", sum}')
    echo "$uid,$purchase_count,$total_spent" >> "$TEMP_RESULTS"
done

# Read back from TEMP_RESULTS to display
echo "  Aggregated results from $TEMP_RESULTS:"
cat "$TEMP_RESULTS" | sed 's/^/    /'
echo ""

# --- Stage 4: Generate Summary Report ---
echo "[Stage 4] Generating summary report into $TEMP_SUMMARY"

# Read from multiple temp files to build the summary
TOTAL_RECORDS=$(tail -n +2 "$TEMP_INPUT" | wc -l)
TOTAL_PURCHASES=$(tail -n +2 "$TEMP_PROCESSED" | wc -l)
TOTAL_LOGINS=$(grep ",login," "$TEMP_INPUT" | wc -l)
TOTAL_LOGOUTS=$(grep ",logout," "$TEMP_INPUT" | wc -l)
UNIQUE_USERS=$(tail -n +2 "$TEMP_RESULTS" | wc -l)
GRAND_TOTAL=$(tail -n +2 "$TEMP_RESULTS" | cut -d',' -f3 | \
    awk '{sum += $1} END {printf "%.2f", sum}')
AVG_PURCHASE=$(echo "$GRAND_TOTAL $TOTAL_PURCHASES" | \
    awk '{if ($2 > 0) printf "%.2f", $1/$2; else print "0.00"}')
TOP_SPENDER=$(tail -n +2 "$TEMP_RESULTS" | sort -t',' -k3 -rn | head -1)
TOP_SPENDER_ID=$(echo "$TOP_SPENDER" | cut -d',' -f1)
TOP_SPENDER_AMOUNT=$(echo "$TOP_SPENDER" | cut -d',' -f3)

# Write summary to TEMP_SUMMARY
cat > "$TEMP_SUMMARY" <<EOF
============================================
       DATA PROCESSING PIPELINE REPORT
============================================
Generated: $(date)
Process ID: $$

--- Input Statistics ---
Total raw records:      $TOTAL_RECORDS
Login events:           $TOTAL_LOGINS
Purchase events:        $TOTAL_PURCHASES
Logout events:          $TOTAL_LOGOUTS

--- Purchase Analysis ---
Unique purchasing users: $UNIQUE_USERS
Total revenue:          \$$GRAND_TOTAL
Average purchase value: \$$AVG_PURCHASE
Top spender:            User $TOP_SPENDER_ID (\$$TOP_SPENDER_AMOUNT)

--- Per-User Breakdown ---
EOF

# Append per-user details by reading from TEMP_RESULTS again
tail -n +2 "$TEMP_RESULTS" | while IFS=',' read -r user_id count spent; do
    printf "  User %-6s: %d purchase(s), total \$%s\n" "$user_id" "$count" "$spent" >> "$TEMP_SUMMARY"
done

cat >> "$TEMP_SUMMARY" <<EOF

--- Temp Files Used ---
  Input:     $TEMP_INPUT
  Processed: $TEMP_PROCESSED
  Results:   $TEMP_RESULTS
  Summary:   $TEMP_SUMMARY
============================================
EOF

# Read and display the final summary from TEMP_SUMMARY
echo ""
cat "$TEMP_SUMMARY"
echo ""

# --- Stage 5: Verify all temp files exist and show their sizes ---
echo "[Stage 5] Temp file inventory:"
for tmpfile in "$TEMP_INPUT" "$TEMP_PROCESSED" "$TEMP_RESULTS" "$TEMP_SUMMARY"; do
    if [ -f "$tmpfile" ]; then
        file_size=$(du -h "$tmpfile" | cut -f1)
        line_count=$(wc -l < "$tmpfile")
        echo "  ✓ $tmpfile (${file_size}, ${line_count} lines)"
    else
        echo "  ✗ $tmpfile (MISSING)"
    fi
done
echo ""

# --- Cleanup ---
echo "[Cleanup] Removing temporary files..."
for tmpfile in "$TEMP_INPUT" "$TEMP_PROCESSED" "$TEMP_RESULTS" "$TEMP_SUMMARY"; do
    if [ -f "$tmpfile" ]; then
        rm -f "$tmpfile"
        echo "  Removed: $tmpfile"
    fi
done

echo ""
echo "=== Pipeline Complete ==="